function parsePre(pre) {
  return pre.split('.').map(function (id) {
    return /^\d+$/.test(id) ? { numeric: true, value: parseInt(id, 10) } : { numeric: false, value: id };
  });
}

function comparePre(a, b) {
  // release beats pre-release
  if (!a && !b) return 0;
  if (!a) return 1;
  if (!b) return -1;

  const aParts = parsePre(a);
  const bParts = parsePre(b);
  const len = Math.max(aParts.length, bParts.length);

  for (let i = 0; i < len; i++) {
    if (i >= aParts.length) return -1; // fewer fields = lower precedence
    if (i >= bParts.length) return 1;
    const ai = aParts[i];
    const bi = bParts[i];
    if (ai.numeric && bi.numeric) {
      if (ai.value !== bi.value) return ai.value - bi.value;
    } else if (!ai.numeric && !bi.numeric) {
      if (ai.value < bi.value) return -1;
      if (ai.value > bi.value) return 1;
    } else {
      // numeric < alphabetic per SemVer 2.0.0 §11.4.1
      return ai.numeric ? -1 : 1;
    }
  }
  return 0;
}

function parseVersion(str) {
  // Strip build metadata before parsing; preserve original string for output
  const plusIdx = str.indexOf('+');
  const core = plusIdx === -1 ? str : str.slice(0, plusIdx);
  const dashIdx = core.indexOf('-');
  const numPart = dashIdx === -1 ? core : core.slice(0, dashIdx);
  const pre = dashIdx === -1 ? null : core.slice(dashIdx + 1);
  const [major, minor, patch] = numPart.split('.').map(Number);
  return { major, minor, patch, pre };
}

function compareVersions(a, b) {
  const pa = parseVersion(a);
  const pb = parseVersion(b);
  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;
  return comparePre(pa.pre, pb.pre);
}

function sortVersions(versions) {
  return versions.slice().sort(compareVersions);
}

