const { sortVersions } = require('./src/core/versions.js');

// Basic numeric core ordering
console.assert(JSON.stringify(sortVersions(['1.10.0','1.2.0'])) === JSON.stringify(['1.2.0','1.10.0']), 'numeric major.minor.patch');

// Pre-release lower than release
console.assert(JSON.stringify(sortVersions(['1.0.0','1.0.0-rc.1'])) === JSON.stringify(['1.0.0-rc.1','1.0.0']), 'pre < release');

// Pre-release identifier comparison (numeric)
console.assert(JSON.stringify(sortVersions(['1.0.0-alpha.10','1.0.0-alpha.2'])) === JSON.stringify(['1.0.0-alpha.2','1.0.0-alpha.10']), 'numeric pre identifiers');

// Pre-release identifier comparison (alpha)
console.assert(JSON.stringify(sortVersions(['1.0.0-rc','1.0.0-alpha'])) === JSON.stringify(['1.0.0-alpha','1.0.0-rc']), 'alpha pre identifiers');

// More fields = higher precedence
console.assert(JSON.stringify(sortVersions(['1.0.0-alpha.1','1.0.0-alpha'])) === JSON.stringify(['1.0.0-alpha','1.0.0-alpha.1']), 'more fields higher');

// Build metadata ignored, strings preserved verbatim
const sorted = sortVersions(['1.0.0+build.9','1.0.0+build.5']);
console.assert(sorted[0] === '1.0.0+build.9' || sorted[0] === '1.0.0+build.5', 'build metadata preserved verbatim');

// Input not mutated
const input = ['1.10.0','1.2.0'];
const orig = input.slice();
sortVersions(input);
console.assert(JSON.stringify(input) === JSON.stringify(orig), 'input not mutated');

console.log('All assertions passed');
